import React, { useEffect, useState } from "react";
import axios from "axios";
import jsPDF from "jspdf";
import html2canvas from "html2canvas";
import "./Billing.css";

const API_URL = "http://localhost:5000/api";

const Billing = () => {
  const [bills, setBills] = useState([]);
  const [form, setForm] = useState({
    patientName: "",
    doctorName: "",
    consultationFee: "",
    medicineFee: "",
    labFee: "",
  });
  const [activeQr, setActiveQr] = useState(null);

  const fetchBills = async () => {
    const res = await axios.get(`${API_URL}/bills`);
    setBills(res.data.data || []);
  };

  useEffect(() => {
    fetchBills();
  }, []);

  useEffect(() => {
    const interval = setInterval(async () => {
      if (!activeQr?.id) return;

      try {
        const res = await axios.get(`${API_URL}/payments/qr/${activeQr.id}`);
        if (res.data.qr.status === "closed") {
          alert("Payment Received ✅");
          setActiveQr(null);
          fetchBills();
        }
      } catch (err) {
        console.log(err);
      }
    }, 5000);

    return () => clearInterval(interval);
  }, [activeQr]);

  const handleChange = (e) => {
    setForm({ ...form, [e.target.name]: e.target.value });
  };

  const createBill = async () => {
    const total =
      Number(form.consultationFee) +
      Number(form.medicineFee) +
      Number(form.labFee);

    const bill = {
      billId: "BILL-" + Date.now(),
      patientName: form.patientName,
      doctorName: form.doctorName,
      consultationFee: Number(form.consultationFee),
      medicineFee: Number(form.medicineFee),
      labFee: Number(form.labFee),
      totalAmount: total,
      paymentStatus: "Pending",
    };

    await axios.post(`${API_URL}/bills`, bill);
    fetchBills();
    alert("Bill Created Successfully");

    setForm({
      patientName: "",
      doctorName: "",
      consultationFee: "",
      medicineFee: "",
      labFee: "",
    });
  };

  const handlePay = async (bill) => {
    try {
      const res = await axios.post(`${API_URL}/payments/create-order`, {
        amount: bill.totalAmount,
      });

      const options = {
        key: res.data.key,
        amount: res.data.order.amount,
        currency: "INR",
        name: "HospitalHub",
        description: "Bill Payment",
        order_id: res.data.order.id,
        handler: async function (response) {
          await axios.post(`${API_URL}/payments/verify`, {
            ...response,
            billId: bill.billId,
          });
          alert("Payment Successful");
          fetchBills();
        },
      };

      const rzp = new window.Razorpay(options);
      rzp.open();
    } catch (err) {
      console.error(err);
      alert("Payment Failed");
    }
  };

  const generateQR = async (bill) => {
    try {
      const res = await axios.post(`${API_URL}/payments/create-qr`, {
        amount: bill.totalAmount,
        billId: bill.billId,
        patientName: bill.patientName,
      });

      setActiveQr(res.data.qr);
    } catch (err) {
      console.error(err);
      alert("QR Generation Failed");
    }
  };

  const printBill = (bill) => {
    const content = `
      <h2>🏥 Hospital Invoice</h2>
      <p>Bill ID: ${bill.billId}</p>
      <p>Patient: ${bill.patientName}</p>
      <p>Doctor: ${bill.doctorName}</p>
      <p>Total: ₹${bill.totalAmount}</p>
      <p>Status: ${bill.paymentStatus}</p>
    `;

    const win = window.open("", "", "width=700,height=700");
    win.document.write(content);
    win.print();
  };

  const generatePDF = async (bill) => {
    const element = document.createElement("div");

    element.innerHTML = `
      <div style="padding:20px;font-family:Arial;background:white">
        <h2>🏥 HospitalHub Invoice</h2>
        <hr/>
        <p><strong>Bill ID:</strong> ${bill.billId}</p>
        <p><strong>Patient:</strong> ${bill.patientName}</p>
        <p><strong>Doctor:</strong> ${bill.doctorName}</p>

        <table border="1" width="100%" style="margin-top:10px;border-collapse:collapse">
          <tr><th>Item</th><th>Amount</th></tr>
          <tr><td>Consultation</td><td>₹${bill.consultationFee}</td></tr>
          <tr><td>Medicine</td><td>₹${bill.medicineFee}</td></tr>
          <tr><td>Lab</td><td>₹${bill.labFee}</td></tr>
          <tr><td><b>Total</b></td><td><b>₹${bill.totalAmount}</b></td></tr>
        </table>

        <p style="margin-top:16px">Status: ${bill.paymentStatus}</p>
      </div>
    `;

    document.body.appendChild(element);

    const canvas = await html2canvas(element);
    const imgData = canvas.toDataURL("image/png");

    const pdf = new jsPDF();
    pdf.addImage(imgData, "PNG", 10, 10, 180, 0);
    pdf.save(`${bill.billId}.pdf`);

    document.body.removeChild(element);
  };

  return (
    <div className="billing-page">
      <div className="billing-header">
        <h2>Billing System</h2>
        <p>Create bills, collect payments, generate QR, print and export invoices</p>
      </div>

      <div className="billing-form-card">
        <h3>Create Bill</h3>
        <div className="billing-form-grid">
          <input name="patientName" placeholder="Patient Name" value={form.patientName} onChange={handleChange} />
          <input name="doctorName" placeholder="Doctor Name" value={form.doctorName} onChange={handleChange} />
          <input name="consultationFee" placeholder="Consultation Fee" value={form.consultationFee} onChange={handleChange} />
          <input name="medicineFee" placeholder="Medicine Fee" value={form.medicineFee} onChange={handleChange} />
          <input name="labFee" placeholder="Lab Fee" value={form.labFee} onChange={handleChange} />
        </div>
        <button className="primary-btn" onClick={createBill}>Create Bill</button>
      </div>

      <div className="billing-table-card">
        <h3>Billing Records</h3>
        <table className="modern-table">
          <thead>
            <tr>
              <th>Bill ID</th>
              <th>Patient</th>
              <th>Total</th>
              <th>Status</th>
              <th>Actions</th>
            </tr>
          </thead>
          <tbody>
            {bills.map((b) => (
              <tr key={b.id}>
                <td>{b.billId}</td>
                <td>{b.patientName}</td>
                <td>₹{b.totalAmount}</td>
                <td>
                  <span className={`status-badge ${b.paymentStatus === "Paid" ? "paid" : "pending"}`}>
                    {b.paymentStatus}
                  </span>
                </td>
                <td className="action-cell">
                  <button onClick={() => handlePay(b)}>Pay</button>
                  <button onClick={() => generateQR(b)}>QR</button>
                  <button onClick={() => printBill(b)}>Print</button>
                  <button onClick={() => generatePDF(b)}>PDF</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {activeQr && (
        <div className="qr-card">
          <h3>Scan to Pay</h3>
          <img src={activeQr.image_url} width="220" alt="QR" />
          <p>Status: {activeQr.status}</p>
        </div>
      )}
    </div>
  );
};

export default Billing;
